func statusAction(ctx context.Context, disabled bool) string {
	if disabled {
		return tr(ctx, "instance.enable")
	}
	return tr(ctx, "instance.disable")
}

func statusTooltip(ctx context.Context, disabled bool) string {
	if disabled {
		return tr(ctx, "tooltip.btn.enable")
	}
	return tr(ctx, "tooltip.btn.disable")
}

func campaignPrivacySummary(ctx context.Context, optional bool) string {
	if optional {
		return tr(ctx, "campaign.privacy.balanced")
	}
	return tr(ctx, "campaign.privacy.strict")
}

func limitMinimum(name string) string {
	if name == "max_members" {
		return "1"
	}
	return "0"
}

func limitMaximum(name string) string {
	switch name {
	case "max_campaigns", "max_members", "max_active_invites":
		return "10000"
	default:
		return "1000000000"
	}
}

